const body = $input.first().json.body || $input.first().json;

const fecha    = body.fecha;
const hora     = body.hora;
const servicio = body.servicio;
const paciente = body.paciente;
const clienteId = body.cliente_id || 1;

const [year, month, day] = fecha.split('-');
const [hour, minute]     = hora.split(':');
const durMin = servicio.duration || 45;
const startDT = new Date(parseInt(year), parseInt(month)-1, parseInt(day), parseInt(hour), parseInt(minute));
const endDT   = new Date(startDT.getTime() + durMin * 60000);
const pad = n => String(n).padStart(2,'0');
const toRFC = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}:00`;

const esc = s => String(s || '').replace(/'/g, "''").substring(0, 200);

const eventoCalendar = {
  summary: `🩺 ${servicio.name} - ${paciente.nombre} ${paciente.apellidos || ''}`.trim(),
  description: [
    `📋 Servicio: ${servicio.name} (${durMin} min)`,
    `👤 Paciente: ${paciente.nombre} ${paciente.apellidos || ''}`,
    `📱 Teléfono: ${paciente.telefono}`,
    `📧 Email: ${paciente.email || 'No facilitado'}`,
    `🔄 Primera visita: ${paciente.primera_visita ? 'Sí' : 'No'}`,
    `📝 Motivo: ${paciente.motivo || 'Sin especificar'}`,
    ``,
    `🤖 Cita agendada automáticamente por Nervia`,
    `📅 ID Cliente: ${clienteId}`
  ].join('\n'),
  start: { dateTime: toRFC(startDT), timeZone: 'Europe/Madrid' },
  end:   { dateTime: toRFC(endDT),   timeZone: 'Europe/Madrid' },
  colorId: '2',
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'email', minutes: 1440 },
      { method: 'popup', minutes: 60 }
    ]
  }
};

return [{
  json: {
    eventoCalendar, body,
    startDateTime: toRFC(startDT),
    endDateTime:   toRFC(endDT),
    // Para DB (valores escapados)
    db: {
      clienteId,
      nombreEsc:    esc(`${paciente.nombre} ${paciente.apellidos || ''}`).trim(),
      emailEsc:     esc(paciente.email),
      telefonoEsc:  esc(paciente.telefono),
      servicioEsc:  esc(servicio.name),
      motivoEsc:    esc(paciente.motivo),
      fecha,
      horaInicio:   hora + ':00',
      horaFin:      `${pad(endDT.getHours())}:${pad(endDT.getMinutes())}:00`,
      origen:       body.origen || 'web',
      esNuevo:      paciente.primera_visita ? 1 : 0
    }
  }
}];

